#include<bits/stdc++.h>
using namespace std;
long long n,l,r,s[100010],a[100010];
struct FHQ_Treap
{
    struct node
    {
        long long l,r;
        long long val,key;
        long long siz;
    }t[200010];
    long long cnt,root;
    stack<long long> s;
    FHQ_Treap():cnt(0){}
    long long newnode(long long v)
    {
        long long x=++cnt;
        t[x].l=t[x].r=0;
        t[x].val=v;
        t[x].key=rand();
        t[x].siz=1;
        return x;
    }
    void pushup(long long x)
    {
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
    }
    void split(long long p,long long v,long long &x,long long &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        if(t[p].val<=v)
        {
            x=p;
            split(t[x].r,v,t[x].r,y);
        }
        else
        {
            y=p;
            split(t[y].l,v,x,t[y].l);
        }
        pushup(p);
    }
    long long merge(long long x,long long y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        if(t[x].key<t[y].key)
        {
            t[x].r=merge(t[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            t[y].l=merge(x,t[y].l);
            pushup(y);
            return y;
        }
    }
    void insert(long long v)
    {
        long long x,y,z;
        split(root,v,x,y);
        z=newnode(v);
        root=merge(merge(x,z),y);
    }
    void del(long long v)
    {
        long long x,y,z;
        split(root,v,x,z);
        split(x,v-1,x,y);
        y=merge(t[y].l,t[y].r);
        root=merge(merge(x,y),z);
    }
    long long getrnk(long long v)
    {
        long long x,y;
        split(root,v-1,x,y);
        long long ans=t[x].siz+1;
        root=merge(x,y);
        return ans;
    }
    long long kth(long long x,long long k)
    {
        if(k==t[t[x].l].siz+1)
        {
            return x;
        }
        if(k<=t[t[x].l].siz)
        {
            return kth(t[x].l,k);
        }
        else
        {
            return kth(t[x].r,k-t[t[x].l].siz-1);
        }
    }
    long long getkth(long long x)
    {
        return t[kth(root,x)].val;
    }
    long long getpre(long long x)
    {
        return getkth(getrnk(x)-1);
    }
    long long getnxt(long long x)
    {
        return getkth(getrnk(x+1));
    }
}t;
int main()
{
    scanf("%lld%lld%lld",&n,&l,&r);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        s[i]=s[i-1]+a[i];
    }
    long long ans=0;
    t.insert(0);
    for(long long i=1;i<=n;i++)
    {
        ans+=t.getrnk(1ll*s[i]-l+1)-t.getrnk(1ll*s[i]-r);
        t.insert(s[i]);
    }
    printf("%lld",ans);
    return 0;
}
